1	type Item = { type: string };
2	type Step = { op: "quote"; items: Item[] };
3	type Customer = { yearsWithMHPCO: number };
4	type Scenario = { customer: Customer; steps: Step[] };
5	type QuoteResult = { premium: number };
6	
7	const PROCESSING_FEE = 5;
8	const FIRST_INSURANCE_RATE = 0.1;
9	
10	const BASE_PREMIUMS: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	};
15	
16	const quoteStep = (step: Step): QuoteResult => {
17	  const itemsBase = step.items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
18	  const firstInsurance = itemsBase * FIRST_INSURANCE_RATE;
19	  const premium = Math.ceil(itemsBase + firstInsurance) + PROCESSING_FEE;
20	  return { premium };
21	};
22	
23	export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => {
24	  const results = scenario.steps.map(quoteStep);
25	  return { results };
26	};
27

